    void process_packet(const char* data, std::size_t length) {
        // Simple packet structure: [id(16 bytes)][x(4 bytes)][y(4 bytes)][isShooting(1 byte)]
        Player player;
        std::memcpy(player.id.data(), data, 16);
        player.x = *reinterpret_cast<const float*>(data + 16);
        player.y = *reinterpret_cast<const float*>(data + 20);
        player.isShooting = static_cast<bool>(data[24]);

        players_[player.id] = player;

        // For simplicity, no packet validation and immediate processing
        std::cout << "Player " << player.id << " updated position to (" << player.x << ", " << player.y << ")"
                  << (player.isShooting ? " and is shooting!" : "") << std::endl;
    }

    asio::io_service io_service_;
    udp::socket socket_;
    udp::endpoint remote_endpoint_;
    std::array<char, 1024> recv_buffer_;
    std::unordered_map<std::string, Player> players_;
